proof:
have h_indep : iIndepFun (fun (p : α × ℕ) ↦ rewardByCount p.1 p.2) (Bandit.measure alg ν) := by
  exact iIndepFun_rewardByCount alg ν
have h_indep : Indep (⨆ s, MeasurableSpace.comap (fun ω => rewardByCount a s ω) inferInstance) (⨆ s, MeasurableSpace.comap (fun ω => rewardByCount b s ω) inferInstance) (Bandit.measure alg ν) := by
  have h_indep : Indep (⨆ p ∈ ({a} ×ˢ Set.univ : Set (α × ℕ)), MeasurableSpace.comap (fun ω => rewardByCount p.1 p.2 ω) inferInstance) (⨆ p ∈ ({b} ×ˢ Set.univ : Set (α × ℕ)), MeasurableSpace.comap (fun ω => rewardByCount p.1 p.2 ω) inferInstance) (Bandit.measure alg ν) := by
    apply_rules [ ProbabilityTheory.indep_iSup_of_disjoint ];
    · intro p; exact (by
      apply_rules [ Measurable.comap_le, measurable_rewardByCount ]);
    · simp +decide [ hab, Set.disjoint_left ];
  convert h_indep using 1;
  · refine' le_antisymm _ _ <;> simp +decide [ iSup_le_iff ];
    · intro i; exact le_iSup₂_of_le ( a, i ) rfl le_rfl;
    · exact fun a b ha => le_iSup_of_le b <| by aesop;
  · refine' le_antisymm _ _ <;> simp +decide [ iSup_le_iff ];
    · intro i; exact le_iSup₂_of_le ( b, i ) rfl le_rfl;
    · exact fun a n hn => le_iSup_of_le n ( by aesop );
convert h_indep using 1;
ext; simp [IndepFun, Indep];
simp +decide [ Kernel.IndepFun, Kernel.Indep ];
convert Iff.rfl;
· exact Eq.symm MeasurableSpace.comap_pi
· exact Eq.symm MeasurableSpace.comap_pi

